<!doctype html><html><head><meta charset="utf-8"><style>body{font-family:DejaVu Sans,sans-serif;color:#152033;font-size:11px}h1,h2{font-family:DejaVu Serif,serif;color:#06284f}.header{border-bottom:3px solid #0d7bd8;padding-bottom:12px;margin-bottom:18px}.meta{width:100%;border-collapse:collapse}.meta td{padding:4px;border-bottom:1px solid #ddd}.result{margin:12px 0;padding:10px;border:1px solid #dfe5ee;border-radius:6px}.label{font-weight:bold;color:#06284f}.photo{margin:14px 0;page-break-inside:avoid}.photo img{max-width:520px;max-height:350px}.footer{margin-top:20px;color:#6e7b8f;font-size:9px}</style></head><body><div class="header"><h1>Rock Bluffs Exterior Services</h1><h2><?=e($inspection['template_name'])?> Inspection Packet</h2></div><table class="meta"><tr><td><strong>Inspection:</strong> #<?=e($inspection['id'])?></td><td><strong>Status:</strong> <?=e($inspection['status'])?></td></tr><tr><td><strong>Job:</strong> <?=e($inspection['job_number']?:'—')?></td><td><strong>Customer:</strong> <?=e($inspection['customer_name']?:'—')?></td></tr><tr><td colspan="2"><strong>Property:</strong> <?=e(trim(($inspection['address1']??'').' '.($inspection['city']??'').' '.($inspection['state']??'').' '.($inspection['postal_code']??'')))?></td></tr><tr><td><strong>Completed by:</strong> <?=e($inspection['completed_name']?:'—')?></td><td><strong>Completed:</strong> <?=e($inspection['completed_at']?:'—')?></td></tr></table><h2>Responses</h2><?php foreach($items->fetchAll() as $item):?><div class="result"><div class="label"><?=e($item['label'])?></div><div><?=nl2br(e($item['response_text']??'—'))?></div></div><?php endforeach?><h2>Attachments</h2><?php foreach($attachments->fetchAll() as $a):$path=dirname(__DIR__,2).'/storage/uploads/'.$a['storage_path'];?><div class="photo"><div class="label"><?=e($a['caption']?:$a['attachment_type'])?></div><?php if(is_file($path)&&str_starts_with($a['mime_type'],'image/')):?><img src="data:<?=e($a['mime_type'])?>;base64,<?=base64_encode(file_get_contents($path))?>"><?php else:?><p><?=e($a['filename'])?></p><?php endif?></div><?php endforeach?><div class="footer">Generated <?=date('F j, Y g:i A')?> by Rock Bluffs Exterior Services.</div></body></html>
